+/// Truncate a response body string to `max` characters at a safe UTF-8 boundary.
+fn truncate_body(body: String, max: usize) -> String {
+    if body.len() <= max {
+        return body;
+    }
+    // Find the last char boundary at or before `max` bytes
+    let end = body
+        .char_indices()
+        .map(|(i, _)| i)
+        .take_while(|&i| i <= max)
+        .last()
+        .unwrap_or(0);
+    format!("{}...[truncated]", &body[..end])
+}
